   }
 }

 const total = tickets.length;
 return tickets
   .sort((a, b) => (a.ordem || 0) - (b.ordem || 0))
   .map((t, i) => ({ json: {
     phone_waha:   phoneWaha,
     qr_url:       t.qr_url,
     token:        t.token,
     nome_tipo:    t.nome_tipo,
     ordem:        t.ordem || i + 1,
     senha_label:  'Senha ' + (t.ordem || i + 1) + ' de ' + total,
     evento_nome:  (evento.nome || '').trim(),
     aluno_nome:   aluno?.nome_completo || '',
     aluno_serie:  aluno?.serie || '',
     evento_data:  evento.data_evento || '',
     evento_local: evento.local || '',
   }}));
